    18→const ConfirmOwnership = lazy(
    19→  () =>
    20→    import(
    21→      './Settings/pages/accountSetup/OrganizationInfo/ChangeOwner/components/ConfirmOwnership/ConfirmOwnership'
    22→    )
    23→);
