    26→const DashboardV2 = lazy(() => import('./DashboardV2/Dashboard'));
    27→const EventActionPageView = lazy(
    28→  () => import('src/builder/PublicActionPage/ActionPageView/ActionPageView')
    29→);
    30→const ForceErrorPage = lazy(() => import('./components/ForceErrorPage/ForceErrorPage'));
