    53→export const useRouteConfig = (filter?: (route: RouteOption) => boolean): RouteOption[] => {
    54→  const actionPagesRoutes = useActionPagesRoutes(filter);
    55→  const relationshipRoutes = useRelationshipRoutes(filter);
    56→  const financeRoutes = useFinanceRoutes(filter);
    57→  const settingsRoutes = useSettingsRoutes(filter);
    58→  const donorApplicationRoutes = useDonorApplicationRoutes();
    59→  const adminRoutes = useAdminRoutes();
    60→
    61→  const routes: RouteOption[] = useMemo(() => {
    62→    const accountRoutes: RouteOption[] = [
    63→      {
    64→        path: '',
    65→        index: true,
    66→        element: <Navigate replace to="dashboard" />,
    67→      },
    68→      ...actionPagesRoutes,
    69→      ...relationshipRoutes,
    70→      ...financeRoutes,
    71→      ...settingsRoutes,
    72→      {
    73→        element: <Builder />,
    74→        path: 'builder/*',
    75→      },
    76→      {
    77→        element: <ConfirmOwnership />,
    78→        id: 'ownership',
    79→        path: 'ownership',
    80→      },
    81→      {
    82→        element: <Dashboard />,
    83→        path: 'dashboard',
    84→      },
    85→      {
    86→        element: <DashboardV2 />,
    87→        path: 'dashboard_v2',
    88→      },
    89→      {
    90→        element: <OrganizationApplication />,
    91→        path: 'application/*',
    92→      },
    93→      {
    94→        element: <OrganizationSetup />,
    95→        path: 'setup/*',
    96→      },
    97→    ].filter(filter || Boolean);
    98→
    99→    const applicationRoute: RouteOption = {
   100→      element: <NewAccountApplication />,
   101→      path: 'accounts/application',
   102→    };
   103→
   104→    const accountWrapper: RouteOption = {
   105→      element: <AccountSwitch />,
   106→      path: 'accounts/:accountId',
   107→      children: accountRoutes,
   108→    };
   109→
   110→    const otherRoutes: RouteOption[] = [
   111→      {
   112→        element: <Admin />,
   113→        path: 'staff/*',
   114→        children: [...adminRoutes],
   115→      },
   116→      {
   117→        element: <OauthRedirectPage />,
   118→        path: 'oauth-redirect',
   119→      },
   120→      {
   121→        element: <OauthRedirectPage />,
   122→        path: 'oauth-redirect/:service',
   123→      },
   124→      {
   125→        element: <ForceErrorPage />,
   126→        path: 'qa/test/force-error',
   127→      },
   128→      {
   129→        path: ':accountSlug/storefront',
   130→        children: [
   131→          {
   132→            element: <PublicActionPageConfirmation />,
   133→            path: 'checkout/submissions/:submissionId/receipt',
   134→          },
   135→          {
   136→            element: <Storefront />,
   137→            index: true,
   138→            path: '*',
   139→          } as RouteOption,
   140→        ],
   141→      },
   142→      // Need a separate route for events in the case of custom domains
   143→      {
   144→        path: 'events/:actionPageSlug',
   145→        children: [
   146→          {
   147→            element: <EventActionPageView />,
   148→            index: true,
   149→          } as RouteOption,
   150→          {
   151→            element: <PublicActionPageConfirmation />,
   152→            path: 'submissions/:submissionId/receipt',
   153→          },
   154→        ],
   155→      },
   156→      {
   157→        path: ':accountSlug/:actionPageSlug',
   158→        element: <FeaturedVideoWrapper />,
   159→        children: [
   160→          {
   161→            element: <ActionPageView />,
   162→            index: true,
   163→
   164→            // technically for RouteOption (our own type) this needs a path,
   165→            // but to avoid changing runtime behavior leaving it alone
   166→            // and forcing TypeScript to see it as correct.
   167→            // Making RouteOption require path broke TS types in other places.
   168→          } as RouteOption,
   169→          {
   170→            element: <PublicActionPageConfirmation />,
   171→            path: 'submissions/:submissionId/receipt',
   172→          },
   173→          {
   174→            element: <ActionPageView isRestricted />,
   175→            path: 'restricted',
   176→          },
   177→        ],
   178→      },
   179→      {
   180→        path: ':actionPageSlug',
   181→        element: <FeaturedVideoWrapper />,
   182→        children: [
   183→          {
   184→            element: <ActionPageView />,
   185→            index: true,
   186→
   187→            // technically for RouteOption (our own type) this needs a path,
   188→            // but to avoid changing runtime behavior leaving it alone
   189→            // and forcing TypeScript to see it as correct.
   190→            // Making RouteOption require path broke TS types in other places.
   191→          } as RouteOption,
   192→          {
   193→            element: <PublicActionPageConfirmation />,
   194→            path: 'submissions/:submissionId/receipt',
   195→          },
   196→          {
   197→            element: <ActionPageView isRestricted />,
   198→            path: 'restricted',
   199→          },
   200→        ],
   201→      },
   202→      {
   203→        // Legacy event page URL pattern - redirect to the new URL
   204→        element: <EventPageRedirect />,
   205→        path: ':accountSlug/events/:actionPageSlug',
   206→      },
   207→    ];
   208→
   209→    const topLevelRoutes: RouteOption[] = [
   210→      {
   211→        element: <CrimsonTerminal />,
   212→        path: '/crimson/donations/new/*',
   213→      },
   214→      {
   215→        element: <ISPTerminal />,
   216→        path: '/isp/donations/new/*',
   217→      },
   218→      {
   219→        element: <OrganizationList />,
   220→        path: '/accounts',
   221→      },
   222→      {
   223→        element: <UserProfile />,
   224→        path: '/users/:userId/profile',
   225→        children: [
   226→          {
   227→            element: <UserProfileForm />,
   228→            path: 'edit',
   229→          },
   230→          {
   231→            element: <NotificationsForm />,
   232→            path: 'notifications',
   233→          },
   234→          {
   235→            element: <EmailAndSecurityForm />,
   236→            path: 'security',
   237→          },
   238→          {
   239→            element: <UserProfileForm />,
   240→            path: '',
   241→            index: true,
   242→          },
   243→        ],
   244→      },
   245→      {
   246→        element: <Navigate to="/accounts" />,
   247→        path: '/',
   248→      },
   249→    ];
   250→
   251→    const finalRoutes: RouteOption[] = [
   252→      applicationRoute,
   253→      accountWrapper,
   254→      ...donorApplicationRoutes,
   255→      ...otherRoutes,
   256→      ...topLevelRoutes,
   257→    ];
   258→
   259→    return finalRoutes;
   260→  }, [
   261→    actionPagesRoutes,
   262→    adminRoutes,
   263→    donorApplicationRoutes,
   264→    filter,
   265→    financeRoutes,
   266→    relationshipRoutes,
   267→    settingsRoutes,
   268→  ]);
   269→
   270→  return routes;
   271→};
