     5→import { makeSearchParams } from '@utils/params/makeSearchParams';
     6→import { useQuery } from 'react-query';
     7→
     8→export const useShowActionPage = ({
     9→  accountSlug,
    10→  actionPageSlug,
    11→  customDomain,
    12→}: {
    13→  accountSlug?: string;
    14→  actionPageSlug?: string;
    15→  customDomain?: string;
    16→}): {
    17→  actionPage?: PublicActionPage;
    18→  error: IErrorResponse | undefined | null;
    19→  isError: boolean;
    20→  isFetched: boolean;
    21→  isLoading: boolean;
    22→} => {
    23→  const params = makeSearchParams({
    24→    account_slug: accountSlug,
    25→    custom_domain: customDomain,
    26→  });
    27→
    28→  const query = useQuery<PublicActionPage, IErrorResponse>(
    29→    generateQueryKey({
    30→      accountId: accountSlug,
    31→      resourceId: actionPageSlug,
    32→      resourceKey: resourceKeys.actionPagesShow,
    33→    }),
    34→    () => {
    35→      return new ApiClient({ namespace: 'public' }).get<PublicActionPage>(
    36→        `/action_pages/${actionPageSlug}?${params.toString()}`
    37→      );
    38→    },
    39→    {
    40→      enabled: !!actionPageSlug && (!!accountSlug || !!customDomain),
    41→      retry: false,
    42→    }
    43→  );
    44→
    45→  return {
    46→    actionPage: query.data,
    47→    error: query.error,
    48→    isError: query.isLoading,
    49→    isFetched: query.isFetched,
    50→    isLoading: query.isLoading,
    51→  };
    52→};
